let fetchCount = 0;

export function getFetchCount() {
  return fetchCount;
}

export function resetFetchCount() {
  fetchCount = 0;
}

export async function loadData(key, ttl = 1000) {
  fetchCount++;
  return { key, timestamp: Date.now(), fetchNum: fetchCount };
}

export function clearCache() {
  // no-op for now
}

workspace.tests/dataLoader.test.mjs:
import { loadData, clearCache, getFetchCount, resetFetchCount } from '../src/dataLoader.mjs';

const assert = (c, m) => { if (!c) throw new Error(m); };

function delay(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

async function runTests() {
  // Reset state
  resetFetchCount();
  clearCache();

  // Test 1: first call fetches data
  const r1 = await loadData('user:1', 200);
  assert(r1.key === 'user:1', 'Key should be user:1');
  assert(getFetchCount() === 1, 'Should have fetched once but count is ' + getFetchCount());

  // Test 2: second call within TTL returns cached (no new fetch)
  const r2 = await loadData('user:1', 200);
  assert(getFetchCount() === 1, 'Should still be 1 fetch (cached) but count is ' + getFetchCount());
  assert(r2.timestamp === r1.timestamp, 'Cached result should have same timestamp');
  assert(r2.fetchNum === r1.fetchNum, 'Cached result should have same fetchNum');

  // Test 3: different key triggers new fetch
  const r3 = await loadData('user:2', 200);
  assert(getFetchCount() === 2, 'Should be 2 fetches for different key but count is ' + getFetchCount());
  assert(r3.key === 'user:2', 'Key should be user:2');

  // Test 4: after TTL expires, re-fetches
  await delay(250);
  const r4 = await loadData('user:1', 200);
  assert(getFetchCount() === 3, 'Should re-fetch after TTL expiry but count is ' + getFetchCount());
  assert(r4.timestamp > r1.timestamp, 'New fetch should have later timestamp');

  // Test 5: clearCache forces re-fetch
  const r5 = await loadData('user:2', 5000);
  const countBefore = getFetchCount();
  clearCache();
  const r6 = await loadData('user:2', 5000);
  assert(getFetchCount() === countBefore + 1, 'clearCache should force re-fetch but count is ' + getFetchCount());
  assert(r6.fetchNum > r5.fetchNum, 'Should be a new fetch after clearCache');

  console.log('ALL TESTS PASSED');
}

runTests();
